import { NextResponse } from "next/server";
import path from "path";
import fs from "fs";
import { pathToFileURL } from "url";
import { request } from "undici";

type Params = { carId: string; checkId: string };

async function httpGetJson(url: string, headers: Record<string, string>) {
  const res = await request(url, { method: "GET", headers });

  const text = await res.body.text();
  if (res.statusCode < 200 || res.statusCode >= 300) {
    return { ok: false as const, status: res.statusCode, text };
  }

  try {
    return { ok: true as const, status: res.statusCode, json: JSON.parse(text) };
  } catch {
    return { ok: false as const, status: 500, text: "Invalid JSON from upstream" };
  }
}

async function httpGetBuffer(url: string, headers: Record<string, string>) {
  const res = await request(url, { method: "GET", headers });
  const buf = Buffer.from(await res.body.arrayBuffer());

  if (res.statusCode < 200 || res.statusCode >= 300) {
    return { ok: false as const, status: res.statusCode, buf };
  }
  return { ok: true as const, status: res.statusCode, buf };
}

function toDataUrlPng(buf: Buffer) {
  return `data:image/png;base64,${buf.toString("base64")}`;
}
function toDataUrlJpg(buf: Buffer) {
  return `data:image/jpeg;base64,${buf.toString("base64")}`;
}

// เดาง่าย ๆ จาก header/นามสกุล (พอใช้งานจริงได้)
function toDataUrlImage(buf: Buffer, url: string) {
  const u = url.toLowerCase();
  if (u.endsWith(".jpg") || u.endsWith(".jpeg")) return toDataUrlJpg(buf);
  return toDataUrlPng(buf);
}

export async function generateCarReportPdf(req: Request, params: Params | Promise<Params>) {
  try {
    const { carId, checkId } = await params;

    // ✅ BASE URL ของ Flask/API เช่น https://api.xxx.com  (อย่าใช้ NEXT_PUBLIC ถ้าเป็น server-only)
    const flaskBase = process.env.FLASK_API_BASE || process.env.NEXT_PUBLIC_API_BASE_URL;
    if (!flaskBase) return new NextResponse("Missing FLASK_API_BASE", { status: 500 });

    const auth = req.headers.get("authorization") ?? "";
    const cookie = req.headers.get("cookie") ?? "";

    // ถ้าคุณบังคับ token จริง ๆ ให้เปิด
    if (!auth && !cookie) {
      return NextResponse.json({ message: "Missing token" }, { status: 401 });
    }

    const upstreamHeaders: Record<string, string> = {
      ...(auth ? { Authorization: auth } : {}),
      ...(cookie ? { Cookie: cookie } : {}),
    };

    // 1) ดึง report json จาก Flask ด้วย undici (ไม่ใช้ fetch)
    const reportUrl = `${flaskBase}/api/cars/${carId}/checks/${checkId}/report`;
    const r1 = await httpGetJson(reportUrl, upstreamHeaders);
    if (!r1.ok) {
      return new NextResponse(r1.text || "Failed to load report from Flask", { status: r1.status });
    }

    const payload = r1.json;
    const report = payload?.data ?? payload; // flask มักเป็น { data: {...} }

    if (!report?.car) {
      return new NextResponse("Invalid report shape (missing car)", { status: 500 });
    }

    // 2) เตรียม font ไทย (ไฟล์ต้องอยู่ที่ public/fonts/)
    const regularPath = path.join(process.cwd(), "public", "fonts", "NotoSansThai-Regular.ttf");
    if (!fs.existsSync(regularPath)) {
      return new NextResponse(`Thai font not found: ${regularPath}`, { status: 500 });
    }

    // 3) ดึง logo มาเองแล้วแปลงเป็น data URI (กัน react-pdf ไป fetch เอง)
    const logoUrl = `${flaskBase}/static/images/logo2.png`;
    let logoDataUrl: string | null = null;
    const logoRes = await httpGetBuffer(logoUrl, upstreamHeaders);
    if (logoRes.ok) {
      logoDataUrl = toDataUrlImage(logoRes.buf, logoUrl);
    }

    // 4) เตรียมรูปประกอบ (ถ้ามี) ให้เป็น data URI
    const imgUrlsRaw: string[] = [
      report?.images?.check_1 ? `${flaskBase}${report.images.check_1}` : "",
      report?.images?.check_2 ? `${flaskBase}${report.images.check_2}` : "",
      report?.images?.check_3 ? `${flaskBase}${report.images.check_3}` : "",
    ].filter(Boolean);

    const imgDataUrls: string[] = [];
    for (const u of imgUrlsRaw) {
      const imgRes = await httpGetBuffer(u, upstreamHeaders);
      if (imgRes.ok) imgDataUrls.push(toDataUrlImage(imgRes.buf, u));
    }

    // 5) สร้าง PDF ฝั่ง server
    const React = (await import("react")).default;
    const {
      Document,
      Page,
      Text,
      View,
      StyleSheet,
      Image,
      Font,
      renderToBuffer,
    } = await import("@react-pdf/renderer");

    Font.register({
      family: "TH",
      fonts: [{ src: pathToFileURL(regularPath).href, fontWeight: "normal" }],
    });

    const styles = StyleSheet.create({
      page: { padding: 24, fontSize: 10, fontFamily: "TH", color: "#0f172a" },
      title: { fontSize: 14, marginBottom: 10 },
      headerGrid: { flexDirection: "row", justifyContent: "space-between", marginBottom: 12 },
      col: { width: "48%" },
      row: { flexDirection: "row", marginBottom: 4 },
      label: { width: 120 },
      table: { borderWidth: 1, borderColor: "#222" },
      tableRow: { flexDirection: "row", borderBottomWidth: 1, borderBottomColor: "#222" },
      cell: { paddingVertical: 3, paddingHorizontal: 2, borderRightWidth: 1, borderRightColor: "#222" },

      // ปรับคอลัมน์ให้ใกล้เคียงภาพแนบ (A4 แนวนอนยังไม่ได้ทำ—อันนี้ A4 ปกติ)
      colPosition: { width: "10%" },
      colBrand: { width: "10%" },
      colSerial: { width: "12%" },
      colSize: { width: "14%" },
      colPattern: { width: "10%" },
      colPrice: { width: "8%" },
      colTreadNew: { width: "7%" },
      colTreadFirst: { width: "9%" },
      colTreadNow: { width: "9%" },
      colTreadUsed: { width: "7%" },
      colAvg: { width: "8%" },
      colCpk: { width: "6%" },

      imageRow: { flexDirection: "row", gap: 8, marginTop: 8 },
      imageBox: { width: 160, height: 120, borderWidth: 1, borderColor: "#999", objectFit: "cover" },
    });

    const tires = Array.isArray(report?.tires) ? report.tires : [];

    const PdfDoc = () =>
      React.createElement(
        Document,
        null,
        React.createElement(
          Page,
          { size: "A4", style: styles.page },
          logoDataUrl
            ? React.createElement(Image, {
                src: logoDataUrl,
                style: { width: 120, height: 28, marginBottom: 8 },
              })
            : null,

          React.createElement(Text, { style: styles.title }, "รายงานการตรวจเช็ครถ"),

          // Header 2 คอลัมน์ (ให้คล้ายไฟล์แนบ)
          React.createElement(
            View,
            { style: styles.headerGrid },
            React.createElement(
              View,
              { style: styles.col },
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "บจก."),
                React.createElement(Text, null, `: ${report?.car?.company_name ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "ทะเบียนรถ"),
                React.createElement(Text, null, `: ${report?.car?.registration_number ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "วันที่เช็คครั้งแรก"),
                React.createElement(Text, null, `: ${report?.summary?.start_date ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "เลขไมล์เริ่มต้น"),
                React.createElement(Text, null, `: ${report?.summary?.start_mile ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "ระยะทางใช้ไป (กม.)"),
                React.createElement(Text, null, `: ${report?.summary?.distance_used ?? "-"}`)
              )
            ),
            React.createElement(
              View,
              { style: styles.col },
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "สาขา"),
                React.createElement(Text, null, `: ${report?.car?.branch_name ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "ประเภทรถ"),
                React.createElement(Text, null, `: ${report?.car?.type ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "ผู้ขับ"),
                React.createElement(Text, null, `: ${report?.car?.driver ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "วันที่เช็คล่าสุด"),
                React.createElement(Text, null, `: ${report?.summary?.last_date ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "เลขไมล์ล่าสุด"),
                React.createElement(Text, null, `: ${report?.summary?.last_mile ?? "-"}`)
              ),
              React.createElement(
                View,
                { style: styles.row },
                React.createElement(Text, { style: styles.label }, "ครั้งที่"),
                React.createElement(Text, null, `: ${report?.summary?.round ?? "-"}`)
              )
            )
          ),

          // Table header
          React.createElement(Text, { style: { fontSize: 11, marginBottom: 6 } }, "รายการการเช็คยางแต่ละเส้น"),
          React.createElement(
            View,
            { style: styles.table },
            React.createElement(
              View,
              { style: styles.tableRow },
              React.createElement(Text, { style: [styles.cell, styles.colPosition] }, "ตำแหน่งล้อ"),
              React.createElement(Text, { style: [styles.cell, styles.colBrand] }, "ยี่ห้อ"),
              React.createElement(Text, { style: [styles.cell, styles.colSerial] }, "Serial"),
              React.createElement(Text, { style: [styles.cell, styles.colSize] }, "ขนาดยาง"),
              React.createElement(Text, { style: [styles.cell, styles.colPattern] }, "ลายยาง"),
              React.createElement(Text, { style: [styles.cell, styles.colPrice] }, "ราคา/เส้น"),
              React.createElement(Text, { style: [styles.cell, styles.colTreadNew] }, "ดอกใหม่"),
              React.createElement(Text, { style: [styles.cell, styles.colTreadFirst] }, "ดอกครั้งแรก"),
              React.createElement(Text, { style: [styles.cell, styles.colTreadNow] }, "ดอกล่าสุด"),
              React.createElement(Text, { style: [styles.cell, styles.colTreadUsed] }, "ดอกใช้ไป"),
              React.createElement(Text, { style: [styles.cell, styles.colAvg] }, "อัตราเฉลี่ย"),
              React.createElement(Text, { style: [styles.cell, styles.colCpk] }, "CPK")
            ),

            ...tires.map((t: any, i: number) =>
              React.createElement(
                View,
                { key: `${t?.index ?? i}-${t?.serial ?? i}`, style: styles.tableRow },
                React.createElement(Text, { style: [styles.cell, styles.colPosition] }, t?.position || t?.index || "-"),
                React.createElement(Text, { style: [styles.cell, styles.colBrand] }, t?.brand_name ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colSerial] }, t?.serial ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colSize] }, t?.tire_size ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colPattern] }, t?.tire_identity ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colPrice] }, t?.price ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colTreadNew] }, t?.tread_new ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colTreadFirst] }, t?.tread_first ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colTreadNow] }, t?.depth ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colTreadUsed] }, t?.tread_used ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colAvg] }, t?.avg_km_per_mm ?? "-"),
                React.createElement(Text, { style: [styles.cell, styles.colCpk] }, t?.cpk ?? "-")
              )
            )
          ),

          // Images
          imgDataUrls.length
            ? React.createElement(
                View,
                { style: { marginTop: 12 } },
                React.createElement(Text, { style: { fontSize: 11 } }, "รูปประกอบการตรวจเช็ค"),
                React.createElement(
                  View,
                  { style: styles.imageRow },
                  ...imgDataUrls.map((src, idx) =>
                    React.createElement(Image, { key: `img-${idx}`, src, style: styles.imageBox })
                  )
                )
              )
            : null
        )
      );

    const pdfBuffer = await renderToBuffer(React.createElement(PdfDoc));
    const body = new Uint8Array(pdfBuffer);

    return new NextResponse(body, {
      status: 200,
      headers: {
        "Content-Type": "application/pdf",
        "Content-Disposition": `attachment; filename="car-report-${checkId}.pdf"`,
        "Cache-Control": "no-store",
      },
    });
  } catch (e: any) {
    console.error("PDF_ROUTE_ERROR:", e);
    return new NextResponse(e?.message ?? "PDF generation failed", { status: 500 });
  }
}
